// Observation: offer features (e.g. price norm, duration, stops, airline); action: keep/discard or score.
const TOP_K = 200;
const input = msg.payload || {};
const data = input.data || [];
const meta = input.meta || {};
let selected = data;
if (data.length > TOP_K) {
  // Scaffold: take first TOP_K; in production the trained agent would score/select best TOP_K.
  selected = data.slice(0, TOP_K);
}
flow.set('filter_selected', selected);
